    run_migrations_offline()
else:
    run_migrations_online()

def _zip_execution_artifacts(execution_id: int) -> io.BytesIO:
    """
    Walk output/{execution_id}/ and zip all files into an in-memory buffer.
    """
    artifact_dir = os.path.join(working_dir, str(execution_id))

    if not os.path.isdir(artifact_dir):
        raise FileNotFoundError(f"No artifact directory for execution {execution_id}")

    all_files = []
    for root, _, files in os.walk(artifact_dir):
        for filename in files:
            all_files.append(os.path.join(root, filename))

    if not all_files:
        raise FileNotFoundError(f"No artifact found for execution {execution_id}")

    buffer = io.BytesIO()
    with zipfile.ZipFile(buffer, mode="w", compression=zipfile.ZIP_DEFLATED) as zf:
        for file_path in all_files:
            arcname = os.path.relpath(file_path, artifact_dir)
            zf.write(file_path, arcname=arcname)

    buffer.seek(0)
    return buffer

@router.get("/executions/{execution_id}/stream")
async def stream_execution(execution_id: int):
    """
    SSE endpoint — opens a persistent connection and pushes status updates
    every 10 seconds until the execution completes or fails.
    """
    return StreamingResponse(
        _stream_execution(execution_id),
        media_type="text/event-stream",
        headers={
            "Cache-Control": "no-cache",
            "X-Accel-Buffering": "no",
        },
    )

@router.get("/executions/{execution_id}/download")
async def download_execution_artifacts(
    execution_id: int,
    db: AsyncSession = Depends(get_db)
):
    """
    Zip and stream all agent-generated artifacts for a completed execution.
    """
    execution = await crud.get_execution(db, execution_id)
    if not execution:
        raise HTTPException(status_code=404, detail=f"Execution {execution_id} not found")

    if execution.status == ExecutionStatus.PENDING:
        raise HTTPException(status_code=404, detail="Execution is still pending - no artifacts available yet")
    if execution.status == ExecutionStatus.RUNNING:
        raise HTTPException(status_code=404, detail="Execution is still running - artifacts not ready yet")

    try:
        zip_buffer = _zip_execution_artifacts(execution_id)
    except FileNotFoundError as e:
        raise HTTPException(status_code=404, detail=str(e))

    filename = f"execution_{execution_id}_artifacts.zip"
    return StreamingResponse(
        zip_buffer,
        media_type="application/zip",
        headers={"Content-Disposition": f"attachment; filename={filename}"},
    )

def clone_git(git_url: str, work_dir: str) -> None:
    """
    Shallow-clone a public Git repository into work_dir, then strip .git/.
    """
    if not git_url.startswith(("https://", "http://")):
        raise ValueError(
            "Only HTTPS Git URLs are supported "
            "(e.g. https://github.com/user/repo)"
        )

    if not shutil.which("git"):
        raise RuntimeError(
            "git is not installed in this environment. "
            "Add 'git' to your Dockerfile."
        )

    try:
        result = subprocess.run(
            [
                "git", "clone",
                "--depth=1",
                "--single-branch",
                git_url,
                work_dir,
            ],
            capture_output=True,
            text=True,
            timeout=120,
        )
    except subprocess.TimeoutExpired:
        raise RuntimeError("Git clone timed out after 120 seconds.")
    except FileNotFoundError:
        raise RuntimeError("git binary not found — install git in your environment")

    if result.returncode != 0:
        err = result.stderr.strip()
        if "Repository not found" in err or "not found" in err.lower():
            raise ValueError(f"Repository not found or not accessible: {git_url}")
        if "Authentication failed" in err:
            raise ValueError("Authentication failed — only public repositories are supported")
        raise RuntimeError(f"Git clone failed: {err}")

    _flatten_single_root(work_dir)
    _strip_noise(work_dir)

def _strip_noise(work_dir: str) -> None:
    """
    Recursively remove directories and files that are irrelevant to
    the agent's planning.
    """
    for root, dirs, files in os.walk(work_dir, topdown=False):
        for filename in files:
            if filename in {"DS_Store", "Thumbs.db"}:
                os.remove(os.path.join(root, filename))

        for dirname in dirs:
            if dirname in {".git", ".github", "__pycache__", "node_modules", 
                          ".next", "dist", "build", ".venv", "venv", 
                          ".idea", ".vscode"}:
                full_path = os.path.join(root, dirname)
                shutil.rmtree(full_path, ignore_errors=True)

